"""Binary protocol encoder.

Encodes message dicts into binary wire format per protocol_spec.
"""

import struct
import zlib
from protocol_spec import MSG_TYPE_IDS, MSG_FIELDS, MAGIC, VERSION, HEADER_SIZE, CHECKSUM_SIZE


def encode_field(value, field_type):
    """Encode a single field value to bytes."""
    if field_type == "uint8":
        return struct.pack(">B", value)
    elif field_type == "uint16":
        return struct.pack(">H", value)
    elif field_type == "uint32":
        return struct.pack(">I", value)
    elif field_type == "uint64":
        return struct.pack(">Q", value)
    elif field_type == "bool":
        return struct.pack(">B", 1 if value else 0)
    elif field_type == "string":
        encoded = value.encode("utf-8")
        # TODO: Bug — using 4-byte length prefix instead of 2-byte per spec
        return struct.pack(">I", len(encoded)) + encoded
    elif field_type == "binary":
        # TODO: Bug — using 2-byte length prefix instead of 4-byte per spec
        return struct.pack(">H", len(value)) + value
    else:
        raise ValueError(f"Unknown field type: {field_type}")


def encode_message(msg_type, fields):
    """Encode a complete message.

    Args:
        msg_type: Message type string (e.g., 'PING')
        fields: Dict of field_name -> value

    Returns:
        bytes: Complete encoded message (header + payload + checksum)
    """
    if msg_type not in MSG_TYPE_IDS:
        raise ValueError(f"Unknown message type: {msg_type}")

    type_id = MSG_TYPE_IDS[msg_type]
    field_defs = MSG_FIELDS[msg_type]

    # Encode payload
    payload = b""
    for fname, ftype, fsize in field_defs:
        if fname not in fields:
            raise ValueError(f"Missing field: {fname}")
        payload += encode_field(fields[fname], ftype)

    # Build header
    header = struct.pack(">HBB", MAGIC, VERSION, type_id)
    # TODO: Bug — payload length field is only 2 bytes instead of 4
    header += struct.pack(">H", len(payload))

    # Calculate checksum (CRC32 of payload)
    # TODO: Bug — checksum includes header bytes too
    checksum = zlib.crc32(header + payload) & 0xFFFFFFFF
    checksum_bytes = struct.pack(">I", checksum)

    return header + payload + checksum_bytes

