"""Message construction and validation helpers.

Provides convenient constructors for each message type.
"""

from protocol_spec import MSG_FIELDS, MSG_TYPE_IDS
from encoder import encode_message
from decoder import decode_message, DecodeError


def validate_fields(msg_type, fields):
    """Validate that fields match the spec for a message type.

    Returns:
        (valid: bool, error: str or None)
    """
    if msg_type not in MSG_FIELDS:
        return False, f"Unknown message type: {msg_type}"

    field_defs = MSG_FIELDS[msg_type]
    expected_names = {f[0] for f in field_defs}

    # Check for missing fields
    provided_names = set(fields.keys())
    missing = expected_names - provided_names
    if missing:
        return False, f"Missing fields: {missing}"

    # Check for extra fields
    extra = provided_names - expected_names
    if extra:
        return False, f"Extra fields: {extra}"

    # Validate field types
    for fname, ftype, fsize in field_defs:
        value = fields[fname]
        if ftype in ("uint8", "uint16", "uint32", "uint64"):
            if not isinstance(value, int) or value < 0:
                return False, f"Field {fname}: expected non-negative int, got {type(value).__name__}"
            # TODO: Bug — no upper bound check for each integer type
        elif ftype == "string":
            if not isinstance(value, str):
                return False, f"Field {fname}: expected str, got {type(value).__name__}"
        elif ftype == "binary":
            if not isinstance(value, (bytes, bytearray)):
                return False, f"Field {fname}: expected bytes, got {type(value).__name__}"
        elif ftype == "bool":
            if not isinstance(value, bool):
                return False, f"Field {fname}: expected bool, got {type(value).__name__}"

    return True, None


def make_ping(sequence, timestamp):
    """Create a PING message."""
    fields = {"sequence": sequence, "timestamp": timestamp}
    valid, err = validate_fields("PING", fields)
    if not valid:
        raise ValueError(err)
    return encode_message("PING", fields)


def make_pong(sequence, timestamp, server_time):
    """Create a PONG message."""
    fields = {"sequence": sequence, "timestamp": timestamp, "server_time": server_time}
    valid, err = validate_fields("PONG", fields)
    if not valid:
        raise ValueError(err)
    return encode_message("PONG", fields)


def make_auth_request(username, token, version):
    """Create an AUTH_REQUEST message."""
    fields = {"username": username, "token": token, "version": version}
    valid, err = validate_fields("AUTH_REQUEST", fields)
    if not valid:
        raise ValueError(err)
    return encode_message("AUTH_REQUEST", fields)


def make_auth_response(success, session_id, expires_in):
    """Create an AUTH_RESPONSE message."""
    fields = {"success": success, "session_id": session_id, "expires_in": expires_in}
    valid, err = validate_fields("AUTH_RESPONSE", fields)
    if not valid:
        raise ValueError(err)
    return encode_message("AUTH_RESPONSE", fields)


def make_data_push(channel, sequence, payload, compressed):
    """Create a DATA_PUSH message."""
    fields = {"channel": channel, "sequence": sequence, "payload": payload, "compressed": compressed}
    valid, err = validate_fields("DATA_PUSH", fields)
    if not valid:
        raise ValueError(err)
    return encode_message("DATA_PUSH", fields)


def make_data_ack(channel, sequence, accepted):
    """Create a DATA_ACK message."""
    fields = {"channel": channel, "sequence": sequence, "accepted": accepted}
    valid, err = validate_fields("DATA_ACK", fields)
    if not valid:
        raise ValueError(err)
    return encode_message("DATA_ACK", fields)


def make_error(code, message):
    """Create an ERROR message."""
    fields = {"code": code, "message": message}
    valid, err = validate_fields("ERROR", fields)
    if not valid:
        raise ValueError(err)
    return encode_message("ERROR", fields)
